import{_ as a,a as e,b as d,c as l}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as s,o as i,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const S=JSON.parse('{"title":"新增 S3 相容渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/s3.md","filePath":"zh-TW/upload/s3.md","lastUpdated":1781962217000}'),r={name:"zh-TW/upload/s3.md"};function c(p,t,h,u,b,g){return i(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="新增-s3-相容渠道" tabindex="-1">新增 S3 相容渠道 <a class="header-anchor" href="#新增-s3-相容渠道" aria-label="Permalink to &quot;新增 S3 相容渠道&quot;">​</a></h1><h2 id="適合什麼情境" tabindex="-1">適合什麼情境 <a class="header-anchor" href="#適合什麼情境" aria-label="Permalink to &quot;適合什麼情境&quot;">​</a></h2><ul><li>你想連接任何 S3 相容物件儲存，例如 Cloudflare R2、Backblaze B2、MinIO、AWS S3 等。</li><li>你不想使用 Cloudflare R2 Binding 渠道，或儲存服務不是 Cloudflare R2。</li></ul><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>物件儲存服務的 S3 API 位址</td></tr><tr><td>Bucket 名稱</td><td>檔案存放的 Bucket</td></tr><tr><td>Region</td><td>儲存區域；Cloudflare R2 通常填 <code>auto</code></td></tr><tr><td>Access Key</td><td>S3 存取金鑰</td></tr><tr><td>Secret Key</td><td>S3 私密金鑰</td></tr></tbody></table><p>Cloudflare R2 範例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://你的AccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: imgbed</span></span>
<span class="line"><span>Region: auto</span></span></code></pre></div><h2 id="欄位說明" tabindex="-1">欄位說明 <a class="header-anchor" href="#欄位說明" aria-label="Permalink to &quot;欄位說明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th><th>是否必填</th></tr></thead><tbody><tr><td>渠道名稱</td><td>自己取，例如 <code>R2 S3</code></td><td>是</td></tr><tr><td>Endpoint</td><td>S3 API 位址</td><td>是</td></tr><tr><td>Bucket 名稱</td><td>儲存桶名稱</td><td>是</td></tr><tr><td>Region</td><td>儲存區域，R2 可填 <code>auto</code></td><td>是</td></tr><tr><td>Access Key</td><td>存取金鑰</td><td>是</td></tr><tr><td>Secret Key</td><td>私密金鑰</td><td>是</td></tr><tr><td>Path-style access</td><td>依服務商需求開關</td><td>否</td></tr><tr><td>容量限制</td><td>是否依容量參與調度</td><td>否</td></tr></tbody></table><h2 id="以-cloudflare-r2-建立-s3-token" tabindex="-1">以 Cloudflare R2 建立 S3 Token <a class="header-anchor" href="#以-cloudflare-r2-建立-s3-token" aria-label="Permalink to &quot;以 Cloudflare R2 建立 S3 Token&quot;">​</a></h2><ol><li>登入 Cloudflare。</li><li>進入 <code>R2 Object Storage</code>。</li><li>找到 API Token 入口。</li></ol><p>![R2 API Token 入口](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>建立帳號 API Token。</li></ol><p><img src="`+a+'" alt="建立帳號 API Token" loading="lazy"></p><ol start="5"><li>複製 Access Key ID 和 Secret Access Key。</li></ol><p><img src="'+e+'" alt="複製 Token 值" loading="lazy"></p><h2 id="回-imgbed-填寫-s3-設定" tabindex="-1">回 ImgBed 填寫 S3 設定 <a class="header-anchor" href="#回-imgbed-填寫-s3-設定" aria-label="Permalink to &quot;回 ImgBed 填寫 S3 設定&quot;">​</a></h2><ol><li>打開上傳設定。</li><li>新增渠道。</li><li>選擇 <code>S3</code>。</li><li>填 Endpoint、Bucket、Region、Access Key、Secret Key。</li><li>依服務商需求設定 Path-style access。</li><li>如果要容量控管，再開啟容量限制並填容量上限。</li><li>儲存。</li></ol><p><img src="'+d+'" alt="新增 S3 設定" loading="lazy"></p><h2 id="檢查方式" tabindex="-1">檢查方式 <a class="header-anchor" href="#檢查方式" aria-label="Permalink to &quot;檢查方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>檢查項目</th><th>正常狀態</th></tr></thead><tbody><tr><td>主要欄位已儲存</td><td>詳情頁看得到 Endpoint、Bucket、Region 等資訊</td></tr><tr><td>測試上傳</td><td>上傳圖片後 Bucket 裡會出現檔案</td></tr><tr><td>連結可開啟</td><td>上傳回傳的圖片連結能正常開啟</td></tr><tr><td>容量顯示</td><td>若開啟容量限制，卡片會顯示已用容量與上限</td></tr></tbody></table><p><img src="'+l+`" alt="查詢容量成功" loading="lazy"></p><h2 id="容量統計說明" tabindex="-1">容量統計說明 <a class="header-anchor" href="#容量統計說明" aria-label="Permalink to &quot;容量統計說明&quot;">​</a></h2><p>S3 容量統計是依照 ImgBed 本地 D1 檔案紀錄計算，不是即時掃描服務商 Bucket。</p><p>儲存 S3 設定後，系統會依目前 D1 紀錄重新計算容量帳本。</p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="為什麼上傳失敗" tabindex="-1">為什麼上傳失敗？ <a class="header-anchor" href="#為什麼上傳失敗" aria-label="Permalink to &quot;為什麼上傳失敗？&quot;">​</a></h3><p>優先檢查：</p><ol><li>Endpoint 是否正確。</li><li>Bucket 是否存在。</li><li>Region 是否符合服務商要求。</li><li>Access Key / Secret Key 是否有寫入權限。</li><li>Path-style access 是否符合該服務商需求。</li></ol><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>準備 S3 Endpoint、Bucket、Region、Access Key、Secret Key</span></span>
<span class="line"><span>-&gt; 打開上傳設定</span></span>
<span class="line"><span>-&gt; 新增 S3 渠道</span></span>
<span class="line"><span>-&gt; 填 Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; 依服務商需求調整 Path-style access</span></span>
<span class="line"><span>-&gt; 儲存</span></span>
<span class="line"><span>-&gt; 上傳測試圖片</span></span></code></pre></div>`,31)])])}const y=s(r,[["render",c]]);export{S as __pageData,y as default};
